/**
 * Header_Base Header Builder Module
 * مدیریت هوشمند هدر‌های sticky، کلون و انیمیشن‌های اسکرول
 */
class Header_BaseHeaderBuilder {
    constructor($) {
        this.$ = $;
        this.config = {
            stickyOffset: 300,
            scrollThreshold: 100,
            scrollStickThreshold: 500
        };

        this.state = {
            isSticked: false,
            lastScrollPosition: 0,
            isInitialized: false
        };

        this.elements = {
            header: null,
            banner: null,
            stickyRow: null,
            wpAdminBar: null,
            clone: null
        };

        this.init();
    }

    /**
     * راه‌اندازی اولیه
     */
    init() {
        this.cacheElements();
        this.setupStickyHeader();
        this.setupHeaderClone();
        this.bindEvents();
        this.dispatchInitializedEvent();
    }

    /**
     * کش کردن المان‌های مهم
     */
    cacheElements() {
        this.elements = {
            header: this.$('.whb-header'),
            banner: this.$('.header-banner'),
            stickyRow: this.$('.whb-sticky-row'),
            wpAdminBar: this.$('#wpadminbar'),
            window: Header_BaseThemeModule.$window,
            document: Header_BaseThemeModule.$document,
            body: Header_BaseThemeModule.$body
        };
    }

    /**
     * تنظیم هدر Sticky
     */
    setupStickyHeader() {
        const header = this.elements.header;

        if (!header.hasClass('whb-sticky-real') &&
            !header.hasClass('whb-scroll-slide')) {
            return;
        }

        const stickyRow = this.findActiveStickyRow();

        // بررسی شرایط لازم برای sticky شدن
        if (!this.isValidForSticky(stickyRow)) {
            return;
        }

        // محاسبه offset برای sticky شدن
        this.calculateStickyOffset(header, stickyRow);
    }

    /**
     * پیدا کردن ردیف Sticky فعال
     */
    findActiveStickyRow() {
        let activeRow = '';

        this.elements.stickyRow.each((index, element) => {
            const $row = this.$(element);
            if (element.offsetHeight > 10) {
                activeRow = $row;
                return false; // توقف حلقه
            }
        });

        return activeRow;
    }

    /**
     * بررسی اعتبار برای Sticky شدن
     */
    isValidForSticky(stickyRow) {
        // در حالت ویرایش Elementor هدر sticky کار نمی‌کند
        if (typeof elementorFrontend !== 'undefined' &&
            elementorFrontend.isEditMode()) {
            return false;
        }

        // اگر ردیف sticky وجود نداشته باشد یا ارتفاع کافی نداشته باشد
        if (!stickyRow || stickyRow[0].offsetHeight < 10) {
            return false;
        }

        return true;
    }

    /**
     * محاسبه offset برای Sticky شدن
     */
    calculateStickyOffset(header, stickyRow) {
        const adminBarHeight = this.elements.wpAdminBar.length > 0 ?
            this.elements.wpAdminBar[0].offsetHeight : 0;

        if (header.hasClass('whb-sticky-real')) {
            header.addClass('whb-sticky-prepared');

            // محاسبه offset براساس موقعیت ردیف sticky
            this.config.stickyOffset = Math.ceil(stickyRow.offset().top) - adminBarHeight;
        }

        if (header.hasClass('whb-scroll-slide')) {
            const headerHeight = header.find('.whb-main-header')[0].offsetHeight;
            this.config.stickyOffset = headerHeight + adminBarHeight;
        }
    }

    /**
     * تنظیم کلون هدر (برای حالت sticky-clone)
     */
    setupHeaderClone() {
        const header = this.elements.header;

        if (!header.hasClass('whb-sticky-clone')) {
            return;
        }

        // حذف کلون قبلی
        this.removeExistingClone();

        // ایجاد کلون جدید
        this.createHeaderClone();

        // ارسال رویداد ایجاد کلون
        this.dispatchCloneCreatedEvent();
    }

    /**
     * حذف کلون موجود
     */
    removeExistingClone() {
        const existingClone = this.$('.whb-clone');
        if (existingClone.length) {
            existingClone.remove();
        }
    }

    /**
     * ایجاد کلون جدید از هدر
     */
    createHeaderClone() {
        const header = this.elements.header;
        const cloneData = {
            cloneClass: header.find('.whb-general-header').attr('class')
        };

        // تنظیم کلاس‌های wrapper
        if (header.hasClass('whb-hide-on-scroll')) {
            cloneData.wrapperClasses = 'whb-hide-on-scroll';
        }

        // دریافت الگوی کلون از تنظیمات
        let cloneTemplate = Header_Base_settings.whb_header_clone;

        // جایگزینی متغیرهای داینامیک
        cloneTemplate = this.replaceDynamicTags(cloneTemplate, header, cloneData);

        // تمیز کردن template
        cloneTemplate = this.cleanCloneTemplate(cloneTemplate);

        // اضافه کردن کلون به DOM
        header.after(cloneTemplate);

        // به‌روزرسانی رفرنس و تنظیمات کلون
        this.setupCloneStyles();
    }

    /**
     * جایگزینی تگ‌های داینامیک در template
     */
    replaceDynamicTags(template, header, data) {
        return template.replace(/<%([^%>]+)?%>|{{([^{}]+)}}/g, (match) => {
            const selector = match.slice(2, -2);

            // اگر المان در DOM وجود دارد
            if (header.find(selector).length) {
                return this.$('<div>')
                    .append(header.find(selector).first().clone())
                    .html();
            }

            // اگر داده در آبجکت data وجود دارد
            if (data[selector] !== undefined) {
                return data[selector];
            }

            return '';
        });
    }

    /**
     * تمیز کردن template کلون
     */
    cleanCloneTemplate(template) {
        return template
            .replace(/<link[^>]*>/g, '') // حذف تگ‌های link
            .replace('whb-col-1', '')    // حذف کلاس‌های خاص
            .replace('dropdowns-loading', '');
    }

    /**
     * تنظیم استایل‌های کلون
     */
    setupCloneStyles() {
        const clone = this.elements.header.parent().find('.whb-clone');

        clone.find('.whb-row')
            .removeClass('whb-flex-equal-sides')
            .addClass('whb-flex-flex-middle');
    }

    /**
     * بایند کردن event listeners
     */
    bindEvents() {
        this.bindScrollEvent();
        this.bindCustomEvents();
    }

    /**
     * مدیریت event اسکرول
     */
    bindScrollEvent() {
        this.elements.window.on('scroll', this.handleScroll.bind(this));
    }

    /**
     * هندل کردن اسکرول
     */
    handleScroll() {
        const scrollTop = this.elements.window.scrollTop();
        const windowHeight = this.elements.window.height();
        const documentHeight = this.elements.document.height();

        // محاسبه offset نهایی
        const finalOffset = this.calculateFinalOffset();

        // مدیریت sticky شدن
        this.handleStickyState(scrollTop, finalOffset);

        // مدیریت انیمیشن‌های اسکرول
        if (this.elements.header.hasClass('whb-hide-on-scroll')) {
            this.handleScrollAnimations(
                scrollTop,
                windowHeight,
                documentHeight,
                finalOffset
            );
        }

        // ذخیره موقعیت اسکرول فعلی
        this.state.lastScrollPosition = scrollTop;
    }

    /**
     * محاسبه offset نهایی با در نظر گرفتن بنر
     */
    calculateFinalOffset() {
        let offset = this.config.stickyOffset;
        const header = this.elements.header;

        // اضافه کردن ارتفاع بنر (اگر فعال باشد)
        if (this.elements.banner.length > 0 &&
            this.elements.body.hasClass('header-banner-display')) {
            offset += this.elements.banner[0].offsetHeight;
        }

        // تنظیم برای حالت scroll-stick
        if (!this.$('.close-header-banner').length &&
            header.hasClass('whb-scroll-stick')) {
            offset = this.config.stickyOffset;
        }

        return offset;
    }

    /**
     * مدیریت state sticky شدن
     */
    handleStickyState(scrollTop, offset) {
        const header = this.elements.header;

        if (scrollTop > offset && !this.state.isSticked) {
            this.state.isSticked = true;
            header.addClass('whb-sticked');
            this.resetDropdownStyles();
        }
        else if (scrollTop <= offset && this.state.isSticked) {
            this.state.isSticked = false;
            header.removeClass('whb-sticked');
            this.resetDropdownStyles();
        }
    }

    /**
     * مدیریت انیمیشن‌های اسکرول (مخفی/نمایش هدر)
     */
    handleScrollAnimations(scrollTop, windowHeight, documentHeight, offset) {
        const header = this.elements.header;
        const threshold = header.hasClass('whb-scroll-stick') ?
            this.config.scrollStickThreshold : this.config.scrollThreshold;

        // اسکرول به بالا
        if (this.state.lastScrollPosition > scrollTop && scrollTop > offset) {
            header.addClass('whb-scroll-up');
            header.removeClass('whb-scroll-down');
        }
        // اسکرول به پایین
        else if (scrollTop > this.state.lastScrollPosition &&
            scrollTop + windowHeight !== documentHeight &&
            scrollTop > offset + threshold) {
            header.addClass('whb-scroll-down');
            header.removeClass('whb-scroll-up');
        }
        // در بالای صفحه
        else if (scrollTop <= offset) {
            header.removeClass('whb-scroll-down');
            header.removeClass('whb-scroll-up');
        }
        // در انتهای صفحه
        else if (documentHeight - 5 <= scrollTop + windowHeight) {
            header.addClass('whb-scroll-up');
            header.removeClass('whb-scroll-down');
        }
    }

    /**
     * ریست کردن استایل dropdown‌ها (برای هدرهای boxed)
     */
    resetDropdownStyles() {
        const header = this.elements.header;

        if (header.hasClass('whb-boxed')) {
            this.$('.wd-offsets-calculated .wd-dropdown-menu').attr('style', '');
            this.$('.wd-offsets-calculated').removeClass('wd-offsets-calculated');

            // ارسال رویداد تغییر sticky
            this.elements.window.trigger('wdHeaderBuilderStickyChanged');
        }
    }

    /**
     * بایند کردن رویدادهای سفارشی
     */
    bindCustomEvents() {
        ['wdEventStarted', 'wdUpdatedHeader'].forEach(eventName => {
            window.addEventListener(eventName, () => {
                this.reinitialize();
            });
        });
    }

    /**
     * راه‌اندازی مجدد ماژول
     */
    reinitialize() {
        this.state.isInitialized = false;
        this.init();
    }

    /**
     * ارسال رویداد راه‌اندازی
     */
    dispatchInitializedEvent() {
        this.elements.document.trigger('wdHeaderBuilderInited');
        this.state.isInitialized = true;
    }

    /**
     * ارسال رویداد ایجاد کلون
     */
    dispatchCloneCreatedEvent() {
        window.dispatchEvent(new CustomEvent('wdHeaderBuilderCloneCreated'));
    }

    /**
     * تخریب ماژول (تمیز کردن event listeners)
     */
    destroy() {
        this.elements.window.off('scroll', this.handleScroll);
        this.state.isInitialized = false;
    }
}

// راه‌اندازی خودکار ماژول
(function ($) {
    // منتظر رویداد شروع
    window.addEventListener('wdEventStarted', function () {
        if (typeof Header_BaseThemeModule !== 'undefined') {
            Header_BaseThemeModule.headerBuilderInstance = new Header_BaseHeaderBuilder($);
        }
    });

    // راه‌اندازی فوری (برای سازگاری با کد قدیمی)
    if (typeof Header_BaseThemeModule !== 'undefined') {
        Header_BaseThemeModule.headerBuilder = function () {
            if (!Header_BaseThemeModule.headerBuilderInstance) {
                Header_BaseThemeModule.headerBuilderInstance = new Header_BaseHeaderBuilder($);
            } else {
                Header_BaseThemeModule.headerBuilderInstance.reinitialize();
            }
        };

        // راه‌اندازی اولیه
        Header_BaseThemeModule.headerBuilder();
    }
})(jQuery);